	public static Ret checkUser(User user) {
		if (user == null || Objects.equals(user.getStatus(), User.Status.LOGOUT)) {
			return RetUtils.notExistUser();
		}
		if (!Objects.equals(user.getStatus(), User.Status.NORMAL)) {
			return RetUtils.invalidUser();
		}
		return Ret.ok();
	}

